  config_num=$((i + 1))
  
  hyperfine \
    --setup "rm -rf data/bronze && rm -rf data/silver && rm -rf data/gold" \
    --runs 100 \
    "uv run kedro run --to-nodes=${nodes_configs[$i]} --runner=ParallelRunner --async" \
    --export-json "data/benchmarks/benchmark_${config_num}.json" \
    && wait

done